// 1. FUNZIONI DI SUPPORTO (Noise & Random)
// Devono essere definite fuori dal main

float random (in vec2 st) {
    return fract(sin(dot(st.xy, vec2(12.9898,78.233))) * 43758.5453123);
}

// Rumore di valore (Value Noise) 2D
float noise (in vec2 st) {
    vec2 i = floor(st);
    vec2 f = fract(st);

    // Interpolazione cubica (Smoothstep) per bordi morbidi
    vec2 u = f * f * (3.0 - 2.0 * f);

    float a = random(i);
    float b = random(i + vec2(1.0, 0.0));
    float c = random(i + vec2(0.0, 1.0));
    float d = random(i + vec2(1.0, 1.0));

    return mix(a, b, u.x) +
            (c - a)* u.y * (1.0 - u.x) +
            (d - b) * u.x * u.y;
}

